def make_counter():
    state = [0]         # list is mutable
    def increment():
        state[0] += 1   # mutating, not rebinding — no nonlocal needed
        return state[0]
    return increment

# Same trick with dict:
def make_counter():
    state = {'count': 0}
    def increment():
        state['count'] += 1  # mutating dict, not rebinding
        return state['count']
    return increment

def max_depth(root):
    result = 0
    def dfs(node, depth):
        nonlocal result
        if not node:
            return
        result = max(result, depth)
        dfs(node.left, depth + 1)
        dfs(node.right, depth + 1)
    dfs(root, 1)
    return result

# Alternative: use return values instead of nonlocal
def max_depth(root):
    if not root:
        return 0
    return 1 + max(max_depth(root.left), max_depth(root.right))

from functools import lru_cache, cache

@lru_cache(maxsize=None)  # unlimited cache
def fib(n):
    if n < 2:
        return n
    return fib(n-1) + fib(n-2)

fib(100)  # instant — O(n) with memoization

# Python 3.9+: @cache is shorthand for @lru_cache(maxsize=None)
@cache
def solve(i, j):
    if i == 0 or j == 0:
        return 0
    return solve(i-1, j) + solve(i, j-1)

# IMPORTANT: arguments must be hashable (no lists!)
